-- ==========================================================
-- ACCOUNTANTS (11 services)
-- ==========================================================

-- 1. Accountants x Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'accountants',
  'web-design',
  'Accountancy is a profession built on trust, precision, and regulatory compliance, and your website must reflect every one of those qualities from the first click. Prospective clients searching for a new accountant are making a high-stakes decision about who handles their financial affairs, and a dated or poorly structured website immediately undermines confidence. Your site needs to communicate ACCA, ICAEW, or AAT credentials clearly, explain complex services like R&D tax credits or Making Tax Digital compliance in plain language, and provide secure client portal access for document exchange. Unlike consumer-facing businesses, accountancy websites must balance professionalism with approachability, converting cautious visitors who may compare three or four firms before making contact. We build accountancy websites that establish authority from the homepage, guide visitors through your service offerings logically, and make it effortless to book an initial consultation or access their existing client portal.',
  'Most accountancy practices still rely heavily on referrals, but the landscape is shifting. Over sixty percent of business owners now research accountants online before making contact, even when referred by a trusted source. A website that looks outdated, lacks clear credentialing, or makes it difficult to understand your fee structure will lose potential clients to competitors who present themselves more professionally. Your website is now your most important trust signal, operating around the clock when your office is closed and your phones are off.',
  'We design accountancy websites with a compliance-first structure. Every page includes proper credential displays, regulatory body logos, and professional indemnity assurances. We integrate secure client portals, build service pages that translate financial jargon into client-friendly language, and create conversion paths specifically calibrated for the longer decision-making cycle typical of accountancy clients.',
  '[{"title": "Website fails to communicate trust and credentials", "description": "Prospective clients visiting your site need immediate reassurance that you are qualified, regulated, and insured. Many accountancy websites bury ACCA or ICAEW credentials in footer text or omit them entirely, forcing cautious prospects to look elsewhere for a firm that visibly demonstrates its professional standing."}, {"title": "No secure client portal for document exchange", "description": "Accountants handle sensitive financial documents daily, yet many firm websites offer no secure upload or download facility. Clients resort to emailing tax returns, payroll data, and bank statements as unencrypted attachments, creating compliance risks under GDPR and undermining the professional image you work hard to maintain."}, {"title": "Service pages filled with jargon clients cannot parse", "description": "Pages titled with technical terms like Corporation Tax Compliance or Capital Gains Tax Planning mean nothing to a small business owner wondering whether you can help them pay less tax. Jargon-heavy service pages create a barrier between your expertise and the clients who need it most, driving them to competitors who communicate more clearly."}]',
  '[{"title": "Trust-first homepage with credential prominence", "description": "We design homepages that immediately establish your professional authority. Regulatory body logos, qualification badges, and professional indemnity details are positioned prominently above the fold. Client testimonials from verifiable business owners reinforce credibility, and a clear value proposition explains exactly who you help and how."}, {"title": "Integrated secure client portal", "description": "Every accountancy site we build includes a secure, branded client portal for document upload and exchange. Clients can submit records, download completed accounts, and share sensitive financial information through an encrypted system that keeps your practice GDPR-compliant and eliminates the risk of emailed attachments."}, {"title": "Plain-language service pages that convert", "description": "We rewrite every service offering in language your ideal client actually uses. Instead of Corporation Tax Compliance, we create pages answering questions like How can I reduce my company tax bill. Each page includes clear pricing guidance, explains what the client can expect, and ends with a specific call to action for booking a consultation."}]',
  '[{"question": "Can you integrate my existing practice management software with the new website?", "answer": "Yes. We regularly integrate accountancy websites with platforms like Xero, QuickBooks, FreeAgent, TaxCalc, and practice management tools such as Senta and AccountancyManager. This includes client portal connections, automated onboarding forms, and direct booking links that feed into your existing workflow."}, {"question": "How do you handle compliance requirements on accountancy websites?", "answer": "We ensure your site displays all required regulatory information including your ACCA, ICAEW, or AAT registration details, professional indemnity insurance confirmation, anti-money laundering supervision details, and data protection registration. We also build cookie consent and privacy policies that meet current GDPR requirements for handling financial data."}, {"question": "Will the website help me attract clients beyond referrals?", "answer": "Absolutely. We build every accountancy site with search visibility in mind, targeting terms like accountant near me, small business accountant in Kent, and service-specific phrases like R&D tax credit specialist. Combined with proper Google Business Profile optimisation, your site becomes a lead generation tool that works alongside your referral network."}, {"question": "How long does it take to build an accountancy website?", "answer": "Most accountancy websites launch within five to seven weeks. The process includes a discovery session to understand your services and ideal client profile, wireframing and design approval, content creation translating your services into client-friendly language, development with client portal integration, and thorough testing before launch."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Accountants x SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'accountants',
  'seo',
  'When a business owner types accountant near me or small business tax help into Google, the firms appearing in the top three results capture the overwhelming majority of enquiries. For accountancy practices, SEO is not a vanity exercise but a direct pipeline to new client acquisition. The challenge is that accountancy is one of the most competitive local search verticals in the UK, with established practices, national chains like TaxAssist, and directory sites like Bark and Checkatrade all competing for the same keywords. A generic SEO approach will not cut through this competition. Your practice needs a strategy built around the specific services you offer, the types of clients you want to attract, and the geographic areas you serve. We build accountancy SEO campaigns that target high-intent search terms, optimise your Google Business Profile for map pack visibility, and create authoritative content that positions your practice as the obvious local choice.',
  'Referrals alone cannot sustain a growing accountancy practice. The firms that consistently win new clients are those appearing at the top of Google when business owners, contractors, and landlords search for financial help. Without deliberate SEO, your practice is invisible to the thousands of people actively looking for an accountant in your area each month. Every month without a search strategy is a month of enquiries going directly to your competitors.',
  'Accountancy SEO requires targeting specific service niches rather than broad terms. We build dedicated landing pages for each service area such as contractor accountant, landlord tax specialist, or R&D tax credits, then optimise your Google Business Profile with accurate service categories and a review generation strategy focused on Google rather than niche directories.',
  '[{"title": "Invisible for high-value accountancy search terms", "description": "Terms like accountant for limited company or tax advisor for landlords carry enormous commercial intent, yet most practices have no dedicated pages targeting these searches. Without optimised landing pages for each service niche, you lose high-value clients to competitors and national chains who have invested in search visibility."}, {"title": "National chains and directories dominating local results", "description": "TaxAssist, Crunch, and directory platforms invest heavily in SEO for accountancy keywords. They appear above local independent practices in search results, siphoning away clients who would prefer a personal, local service if they could find one. Without a strategy to compete, independent firms are pushed further down the page."}, {"title": "Google Business Profile not generating enquiries", "description": "Many accountancy practices have a Google Business Profile that was set up years ago with incomplete service categories, no regular posts, and a handful of reviews. This profile is your most powerful local search asset, yet neglecting it means you are invisible in the map pack results that generate the most direct calls and direction requests."}]',
  '[{"title": "Service-niche landing page strategy", "description": "We create dedicated, fully optimised pages for every accountancy service you offer. Each page targets specific client types and search terms: contractor IR35 advice, property portfolio tax planning, startup accountancy packages. This granular approach captures high-intent traffic that generic accountant pages miss entirely."}, {"title": "Google Business Profile domination", "description": "We fully optimise your practice profile with precise service categories, regular Google Posts highlighting seasonal deadlines like Self Assessment and year-end accounts, and a structured review generation programme. Practices we manage consistently appear in the top three map pack positions for their target keywords."}, {"title": "Authority content that outranks directories", "description": "We develop a content strategy positioning your practice as a genuine authority. Guides on topics like what expenses can I claim as a sole trader or how to prepare for Making Tax Digital attract organic traffic, build backlinks naturally, and demonstrate expertise that directory listings cannot replicate."}]',
  '[{"question": "Which keywords should my accountancy practice target?", "answer": "We research the exact terms your potential clients use, which vary significantly by client type. A practice targeting contractors needs visibility for IR35 accountant and contractor limited company accountant, while one focused on SMEs needs small business accountant and VAT registration help. We map these keywords to dedicated pages and track rankings monthly."}, {"question": "How do I compete with TaxAssist and other national chains in search results?", "answer": "National chains have domain authority but lack local specificity. We outcompete them by building hyper-local content, generating genuine Google reviews from your actual clients, and creating service pages with depth and expertise that franchise websites cannot match. Independent practices can absolutely outrank chains for local searches."}, {"question": "How long before SEO generates new client enquiries for my practice?", "answer": "Most accountancy practices see ranking improvements within eight to twelve weeks for targeted service-specific terms. Broader competitive terms like accountant plus your town typically require four to six months. We provide monthly reports showing keyword movements, traffic increases, and the actual enquiries generated."}, {"question": "Should I focus on Google Ads or SEO for my accountancy practice?", "answer": "Both have a role, but SEO delivers compounding returns. Google Ads for accountancy keywords can cost eight to fifteen pounds per click, and the traffic stops the moment you pause spending. SEO builds an asset that generates enquiries month after month. We recommend SEO as the foundation with targeted Google Ads for immediate visibility while organic rankings build."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 3. Accountants x Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'accountants',
  'lead-capture',
  'Accountancy practices invest considerable effort driving traffic to their websites through referrals, search visibility, and networking, yet most convert fewer than two percent of visitors into actual enquiries. The problem is not traffic but capture. A prospective client lands on your site, browses your services, perhaps reads a blog post, and then leaves without making contact because the only option is a generic contact form or a phone number they are not ready to call. Accountancy is a considered purchase where prospects research multiple firms before committing, and your website needs mechanisms to capture interest at every stage of that decision process. We build lead capture systems specifically designed for the accountancy client journey, from free tax-saving guides that exchange value for an email address, to intelligent quote calculators that pre-qualify prospects, to automated follow-up sequences that nurture enquiries until they are ready to book a consultation.',
  'The typical accountancy website loses over ninety percent of its visitors without any way to follow up. These are people who actively searched for an accountant, found your site, and showed interest in your services. Without a lead capture system, every one of those visitors is gone forever. Your competitors who capture even a fraction of these visitors with downloadable guides, instant quote tools, or automated email sequences build a pipeline of future clients that yours simply does not have.',
  'Accountancy lead capture must reflect the trust-driven nature of the profession. We build tools that exchange genuine value, such as tax deadline calendars, expense claim checklists, and preliminary savings calculators, for contact details. Every lead magnet is positioned around a specific client pain point, and follow-up sequences are written in the measured, authoritative tone your prospects expect from a financial professional.',
  '[{"title": "Website visitors browse and leave without a trace", "description": "Prospective clients comparing accountancy firms often visit three or four websites in a single session. Without a mechanism to capture their details during that research phase, you have no way to follow up. The prospect forgets your firm name, returns to Google, and contacts whichever competitor they remember or find first."}, {"title": "Only capturing prospects ready to call today", "description": "Most accountancy websites only offer a phone number and a contact form, which only works for the small fraction of visitors ready to commit immediately. The majority are still researching, comparing prices, or not yet at a decision point. These early-stage prospects represent your future clients, and you are losing every single one."}, {"title": "No automated follow-up for stale enquiries", "description": "Even when prospects do make contact, many are not ready to proceed immediately. Without an automated nurture sequence, these warm leads go cold. Your team forgets to follow up, the prospect engages another firm, and the original marketing investment that generated the enquiry is completely wasted."}]',
  '[{"title": "Tax-saving lead magnets that pre-qualify prospects", "description": "We create downloadable resources tailored to your ideal client types. A guide titled Seven Tax Deductions Most Sole Traders Miss attracts exactly the right audience, exchanges genuine value for an email address, and immediately identifies the prospect as a sole trader, letting your team prioritise follow-up based on client type and potential value."}, {"title": "Intelligent quote calculator for instant engagement", "description": "We build interactive tools that let prospects estimate their accountancy fees based on business type, turnover, and services needed. This provides immediate value to the visitor while capturing their details and business information, giving your team a pre-qualified lead with enough context to have a meaningful first conversation."}, {"title": "Automated nurture sequences for the accountancy buying cycle", "description": "We design email sequences that guide captured leads toward booking a consultation. Content includes tax deadline reminders, relevant legislative updates like Making Tax Digital changes, and client success stories. Each email reinforces your expertise and keeps your practice front of mind during the weeks or months before the prospect is ready to switch accountants."}]',
  '[{"question": "What kind of lead magnets work best for accountancy practices?", "answer": "The highest-converting lead magnets for accountants are practical tools and checklists that solve an immediate problem. Tax deadline calendars, expense claim checklists for specific professions, year-end preparation guides, and preliminary tax-saving calculators consistently outperform generic content. The key is specificity: a guide for landlord tax deductions converts far better than a general tax tips document."}, {"question": "Will lead capture feel too salesy for an accountancy practice?", "answer": "Not when done correctly. We position every lead capture mechanism as a genuine value exchange. Offering a free Self Assessment preparation checklist is helpful, not pushy. The follow-up emails provide useful information about tax deadlines and legislative changes rather than aggressive sales messages. The tone matches the professional, advisory relationship your clients expect."}, {"question": "How do you handle GDPR compliance for captured leads?", "answer": "Every lead capture form includes explicit consent checkboxes with clear language about how data will be used. We configure double opt-in for email sequences, provide easy unsubscribe mechanisms, and ensure all captured data is stored in GDPR-compliant systems. As an accountancy practice handling financial data, your compliance standards must be exemplary, and our systems reflect that."}, {"question": "Can lead capture integrate with my existing practice management system?", "answer": "Yes. We connect lead capture forms and email sequences with platforms like Senta, AccountancyManager, Xero Practice Manager, and common CRMs like HubSpot or Mailchimp. New leads can be automatically added to your pipeline with their business type, turnover bracket, and service interest already tagged for efficient follow-up."}]'
)
