-- 4. Accountants x Business Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'accountants',
  'business-automation',
  'Accountancy practices are drowning in repetitive administrative tasks that consume billable hours and frustrate skilled professionals. Every client onboarding involves the same document requests, every Self Assessment season triggers the same reminder emails, and every month-end produces the same reporting cycle. These processes are predictable, repeatable, and ripe for automation, yet most practices still handle them manually, relying on spreadsheets, email threads, and individual memory. Business automation for accountancy practices eliminates this administrative overhead, freeing your qualified team to focus on advisory work that generates higher fees and deeper client relationships. We build automation systems tailored specifically to the accountancy workflow, from client onboarding sequences that collect documents automatically, to deadline reminder systems that chase clients for information without your team lifting a finger, to automated reporting that delivers monthly management accounts to clients on schedule.',
  'The average accountancy practice spends over thirty percent of its time on administrative tasks that generate no direct revenue. Client chasing for missing documents alone can consume days each month. This is time your qualified accountants could spend on advisory work billed at two to three times the rate of compliance work. Automation does not replace your team; it removes the repetitive burden that prevents them from doing their highest-value work and causes burnout during peak periods like January Self Assessment deadlines.',
  'We map every recurring accountancy workflow before building anything. Client onboarding, document collection, Self Assessment reminders, VAT deadline chasing, year-end preparation sequences, and monthly reporting each have specific triggers, timelines, and escalation paths. We build automations that mirror your existing process but execute without manual intervention.',
  '[{"title": "Staff overwhelmed by document chasing during peak periods", "description": "Every Self Assessment season, your team sends hundreds of individual emails requesting documents from clients. Many require multiple follow-ups. This manual chasing consumes weeks of staff time during your busiest period, delays filing, and creates stress that drives employee turnover in an industry already struggling with recruitment."}, {"title": "Client onboarding takes weeks instead of days", "description": "Bringing a new client on board involves engagement letters, anti-money laundering checks, agent authorisation forms, document collection, and software setup. When managed manually through emails and checklists, onboarding stretches to weeks, creating a poor first impression and delaying the start of billable work."}, {"title": "Missed deadlines and penalties from manual tracking", "description": "Tracking filing deadlines across hundreds of clients using spreadsheets and calendar reminders is inherently unreliable. A single missed Corporation Tax or VAT deadline results in penalties for your client, damages your professional reputation, and can trigger formal complaints to your regulatory body."}]',
  '[{"title": "Automated document collection and client chasing", "description": "We build intelligent sequences that request documents from clients at the right time, send escalating reminders on a schedule you define, and notify your team only when manual intervention is needed. During Self Assessment season, this system handles the chasing for your entire client base automatically, freeing your team to focus on the actual accounts preparation."}, {"title": "Streamlined client onboarding in days not weeks", "description": "Our onboarding automation sends engagement letters for e-signature, triggers AML verification checks, delivers document request lists tailored to the client type, and tracks completion in real time. New clients move from signed engagement to active status in days rather than weeks, with your team only stepping in for the advisory welcome meeting."}, {"title": "Deadline management with automated escalation", "description": "We build a centralised deadline tracking system that monitors every filing obligation across your client base. Automated reminders go to clients at defined intervals before each deadline, escalation alerts notify your team when action is overdue, and a dashboard gives partners real-time visibility of approaching deadlines across the entire practice."}]',
  '[{"question": "Will automation work with my existing accountancy software?", "answer": "Yes. We build automations that integrate with Xero, QuickBooks, FreeAgent, Sage, TaxCalc, and practice management platforms like Senta, AccountancyManager, and Capium. We also connect with document signing tools like DocuSign and Adobe Sign, email platforms, and cloud storage systems your practice already uses."}, {"question": "How much time can automation realistically save my practice?", "answer": "Most practices we work with recover ten to fifteen hours per staff member per month through automation of document chasing, onboarding, and deadline management alone. During peak periods like Self Assessment season, the savings are significantly higher. We measure the time saved and provide quarterly reports so you can quantify the return on investment."}, {"question": "Is automation secure enough for handling sensitive financial data?", "answer": "All automations we build use encrypted connections, process data through GDPR-compliant platforms, and follow the same security standards required by your regulatory body. We never store client financial data in unsecured systems, and every automation includes audit trails showing exactly what was sent, to whom, and when."}, {"question": "Can I customise the automated messages sent to my clients?", "answer": "Every automated email, reminder, and notification is written in your practice tone and branded with your identity. We draft all communication templates during the setup phase and refine them based on your feedback. Your clients experience consistent, professional communication that feels personal rather than robotic."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
