-- 6. Accountants x Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'accountants',
  'social-media-setup',
  'Social media for accountancy practices is not about viral content or trending hashtags. It is about establishing a consistent professional presence on the platforms where your prospective clients and referral partners already spend their time. LinkedIn is where business owners research professional advisors. Facebook is where local community groups discuss recommendations for accountants. Google Business Profile is where prospects check reviews before making contact. Yet most accountancy practices either ignore social media entirely or maintain dormant profiles that were set up years ago and never properly completed. A properly configured social media presence for your practice acts as an extension of your brand, a validation point for prospects checking your credibility, and a channel for sharing the kind of practical financial guidance that demonstrates your expertise without giving away the work itself. We set up and optimise accountancy social media profiles that look professional, communicate your specialism, and give prospects another reason to trust you over the competition.',
  'When a prospective client is referred to your practice or finds you through search, the next step is almost always a credibility check. They will look you up on LinkedIn, check your Google reviews, and possibly search Facebook for recommendations. Empty, incomplete, or outdated social profiles actively damage trust. A fully optimised social presence does not require daily posting but it must exist, look professional, and reinforce the same brand message as your website.',
  'We focus accountancy social media setup on LinkedIn and Google Business Profile as the primary platforms, with Facebook configured for local visibility. Each profile is built to reinforce your professional credentials, display client testimonials strategically, and provide a content framework around tax deadlines, legislative changes, and practical financial tips that your team can maintain with minimal time investment.',
  '[{"title": "LinkedIn profile does not reflect practice expertise", "description": "Your personal and company LinkedIn profiles are often the first thing a prospective B2B client checks. Incomplete profiles with outdated descriptions, no company page, and zero activity signal a practice that is not investing in its professional image. Business owners looking for a strategic financial advisor expect to see a credible, active LinkedIn presence."}, {"title": "No Google reviews strategy despite excellent client relationships", "description": "Your practice likely has dozens of satisfied clients who would happily leave a review but have never been asked. Meanwhile, competitors with proactive review strategies display twenty or thirty five-star Google reviews that dominate prospect trust assessments. Without a structured approach, your strongest marketing asset remains completely untapped."}, {"title": "Social profiles disconnected from practice brand", "description": "Many accountancy firms have social profiles created at different times by different team members, each using different logos, descriptions, and contact details. This inconsistency confuses prospects and undermines the professional image you present through your website and in-person interactions."}]',
  '[{"title": "LinkedIn company page and personal profile optimisation", "description": "We build a professional LinkedIn company page showcasing your services, credentials, and client results. We also optimise the personal profiles of partners and senior team members to reflect individual specialisms. Each profile is aligned with your brand, includes proper credentialing, and is structured to attract connection requests from your ideal client types."}, {"title": "Google Business Profile optimisation with review strategy", "description": "We fully optimise your Google Business Profile with accurate service categories, professional imagery, and compelling descriptions. We then implement a structured review request system that makes it easy for satisfied clients to leave Google reviews at the right moment, building the social proof that heavily influences prospect decisions."}, {"title": "Content framework for sustainable social activity", "description": "We create a twelve-month content calendar built around the accountancy year: Self Assessment deadlines, tax year changes, Budget announcements, and Making Tax Digital updates. Each content piece is templated so your team can publish consistently with minimal time investment, maintaining an active, expert presence without requiring daily creative effort."}]',
  '[{"question": "Which social media platforms matter most for accountants?", "answer": "LinkedIn and Google Business Profile are the highest priority for most accountancy practices. LinkedIn drives B2B credibility and referral partner relationships, while Google Business Profile directly influences local search visibility and prospect trust through reviews. Facebook is valuable for community-level visibility, particularly for practices serving sole traders and individuals."}, {"question": "How much time will social media require from my team?", "answer": "Our setup is designed for minimal ongoing time investment. After we configure and optimise all profiles, the content framework we provide requires roughly thirty minutes per week to maintain. This includes sharing pre-templated posts around tax deadlines, commenting on relevant industry updates, and responding to any direct messages or reviews."}, {"question": "Can social media actually generate new clients for an accountancy practice?", "answer": "Social media for accountants works primarily as a trust validator and credibility reinforcer rather than a direct lead generator. When prospects find you through search or referral, optimised social profiles with strong reviews and professional content significantly increase the likelihood they make contact. The indirect effect on client acquisition is substantial and measurable."}, {"question": "Should individual accountants in my practice have their own social profiles?", "answer": "Yes, particularly on LinkedIn. Prospective clients often want to know who will actually handle their accounts. We optimise partner and senior team profiles to showcase individual specialisms, qualifications, and personality while maintaining brand consistency. This personal visibility builds trust and differentiates your practice from faceless national chains."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
